/**
 * Custom debounce hook. Returns a debounced copy of `value` that only
 * updates after `delay` ms have passed without `value` changing.
 * Also reports whether a debounce is currently pending.
 */
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);

    useEffect(() => {
        // If the value already matches, there's nothing pending.
        if (value === debouncedValue) {
            setIsPending(false);
            return;
        }

        setIsPending(true);
        const timeoutId = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Cleanup: clears the timeout on every re-run (new keystroke)
        // AND on unmount, preventing memory leaks / state-after-unmount.
        return () => clearTimeout(timeoutId);
    }, [value, delay, debouncedValue]);

    return [debouncedValue, isPending];
